function solve(nums1) {
    const n = nums1.length;

    // Helper function to check if all numbers in an array have the same parity
    const checkParity = (arr) => {
        if (arr.length === 0) return true;
        const parity = Math.abs(arr[0] % 2); // 0 for even, 1 for odd
        for (let i = 1; i < arr.length; i++) {
            if (Math.abs(arr[i] % 2) !== parity) {
                return false;
            }
        }
        return true;
    };

    // Since n is small (<= 100), we can try to explore the possibilities,
    // but the choices are dependent. We need a search/DP approach or exploit properties.

    // The choices for nums2[i] are:
    // 1. nums1[i]
    // 2. nums1[i] - nums1[j] where j != i

    // The goal is to find a set of choices such that all resulting numbers are all even OR all odd.

    // Let's analyze the parity of the options:
    // Parity(nums2[i]) can be:
    // P(nums1[i])
    // P(nums1[i] - nums1[j]) = P(nums1[i]) XOR P(nums1[j])

    // Since we must choose one option for each i, and all resulting parities must be the same (0 or 1),
    // this suggests a 2-coloring or satisfiability problem, but let's look for simpler properties first.

    // If n is small, maybe we can brute force the parity of the required target (all even or all odd).

    // --- Strategy: Try to make all results ODD, then try to make all results EVEN. ---

    // Let P_i = nums1[i] % 2.
    // Target parity T can be 0 (Even) or 1 (Odd).

    // For each i, we must choose an operation such that P(nums2[i]) == T.

    // Option 1: nums2[i] = nums1[i]. Parity is P_i.
    // Option 2: nums2[i] = nums1[i] - nums1[j]. Parity is P_i XOR P_j.

    // Since we need to choose j for every i that uses Option 2, and the choice of j affects the parity,
    // this still seems complex due to dependency on j.

    // Crucial observation: If n=1, nums2[0] must be nums1[0]. It is trivially all same parity.
    if (n === 1) {
        return true;
    }

    // If there exists any pair (i, j) such that P_i != P_j (i.e., there is at least one even and one odd number in nums1),
    // we might have more flexibility.

    // Consider the required parity T (0 or 1).

    // Try to achieve T=1 (All Odd)
    const canBeAllOdd = () => {
        // For each i, we must be able to choose a parity source P_i' such that P_i' = 1.
        // P_i' must be achievable from {P_i} U {P_i XOR P_j | j != i}.

        // Let's fix a target parity T (0 or 1).
        const checkTargetParity = (T) => {
            // We need to ensure that for every i, there exists *some* valid choice leading to parity T.

            // If T=1 (Odd):
            // For index i, we need:
            // 1. P_i == 1 (Use nums1[i]) OR
            // 2. There exists j != i such that P_i XOR P_j == 1 (Use nums1[i] - nums1[j])

            // If T=0 (Even):
            // For index i, we need:
            // 1. P_i == 0 (Use nums1[i]) OR
            // 2. There exists j != i such that P_i XOR P_j == 0 (Use nums1[i] - nums1[j])

            const P = nums1.map(x => Math.abs(x % 2)); // 0 or 1

            for (let i = 0; i < n; i++) {
                let possible = false;

                // Check Option 1: nums2[i] = nums1[i]
                if (P[i] === T) {
                    possible = true;
                }

                if (!possible) {
                    // Check Option 2: nums2[i] = nums1[i] - nums1[j]
                    for (let j = 0; j < n; j++) {
                        if (i === j) continue;

                        // Parity of difference: P[i] XOR P[j]
                        const diffParity = P[i] ^ P[j];

                        if (diffParity === T) {
                            possible = true;
                            break;
                        }
                    }
                }

                if (!possible) {
                    return false; // Cannot achieve target parity T for index i
                }
            }
            return true; // Can achieve target parity T for all indices
        };

        // The crucial detail missed in the above simple check:
        // The problem requires that *one* set of choices (one choice per i) leads to a uniform parity.
        // The simple check above only verifies if for each i, *some* valid choice exists to hit T.
        // This is sufficient because the choice for i only depends on j != i, and j's choice doesn't constrain i's choice *unless*
        // the problem implied that the set {nums2[i]} must be derived from a single global construction process, which it doesn't.
        // "For each index i, you must choose one of the two options."

        // If we can make every element parity T, then we can construct nums2 such that all elements have parity T.
        return checkTargetParity(1) || checkTargetParity(0);
    };

    return canBeAllOdd();
}

