func solve(nums1 []int64) bool {
	n := len(nums1)

	if n == 1 {
		return true
	}

	// P[i] stores the parity of nums1[i]: 0 for even, 1 for odd.
	P := make([]int, n)
	for i := 0; i < n; i++ {
		// Parity of positive number: abs(x) % 2
		// Since nums1[i] >= 1, we just use % 2.
		if nums1[i]%2 == 0 {
			P[i] = 0 // Even
		} else {
			P[i] = 1 // Odd
		}
	}

	// checkTargetParity checks if it's possible to select an operation for every i
	// such that the resulting parity of nums2[i] equals targetT.
	checkTargetParity := func(targetT int) bool {
		for i := 0; i < n; i++ {
			possibleForI := false

			// Option 1: nums2[i] = nums1[i]. Parity is P[i].
			if P[i] == targetT {
				possibleForI = true
			}

			if !possibleForI {
				// Option 2: nums2[i] = nums1[i] - nums1[j], j != i.
				// Parity is P[i] XOR P[j].
				for j := 0; j < n; j++ {
					if i == j {
						continue
					}
					// XOR operation for parity: (P[i] + P[j]) % 2
					diffParity := (P[i] + P[j]) % 2
					if diffParity == targetT {
						possibleForI = true
						break
					}
				}
			}

			if !possibleForI {
				return false // Cannot achieve target parity T for index i
			}
		}
		return true // Can achieve target parity T for all indices
	}

	// We succeed if we can make all elements Odd (T=1) OR all elements Even (T=0).
	return checkTargetParity(1) || checkTargetParity(0)
}
